    if metadata and isinstance(metadata, dict):
        sanitized_metadata = {}
        for key, value in metadata.items():
            safe_key = sanitize_log_field(str(key))
            safe_value = sanitize_log_field(str(value))
            sanitized_metadata[safe_key] = safe_value
        log_entry['metadata'] = sanitized_metadata
    
    # Write as JSON to prevent log injection
    log_line = json.dumps(log_entry, ensure_ascii=True)
    
